+	// Run with a test-level deadline to prevent test from hanging forever
+	done := make(chan struct{})
+	var versionErr error
+	go func() {
+		_, versionErr = adapter.Version(ctx)
+		close(done)
+	}()
+
+	select {
+	case <-done:
+		if versionErr == nil {
+			t.Error("Version() should timeout")
+		}
